var FMT = ['HWP·DOCX','DOCX·PDF','HWP·DOCX','HWP·DOCX','PPTX·PDF'];
var AITOOL = ['AI Works','PixelDeck+AI Works','AI Works','AI Works','PixelDeck'];

// sub-type classifier for 보고서
function subType(name) {
  if (/반기/.test(name)) return '반기';
  if (/PAO/.test(name)) return 'PAO';
  if (/출장/.test(name)) return '출장';
  if (/결과보고서|결과 보고서/.test(name)) return '결과보고서';
  return '기타';
}

function sc(s) { return s==='Finished'?'sF':s==='Planned'?'sP':s==='Going on'?'sG':'sN'; }
function sl(s) { return s==='Finished'?'완료':s==='Planned'?'예정':s==='Going on'?'진행중':'미확인'; }

document.addEventListener('DOMContentLoaded', function() {
  for (var i = 0; i < 5; i++) buildTbl(i);
});

function buildTbl(idx) {
  var tb = document.getElementById('tb' + idx);
  if (!tb) return;
  var items = DATA[idx];
  var html = '';
  items.forEach(function(item) {
    var sub = idx === 3 ? subType(item.o) : item.c;
    var filterSub = idx === 3 ? subType(item.o) : '';
    var fv = item.s || '';
    html += '<tr data-status="'+fv+'" data-sub="'+(idx===3?subType(item.o):'')+'">' +
      '<td><div class="oname">'+item.o+'</div></td>' +
      '<td><div class="ocomp" style="font-size:.74rem;color:var(--muted);">'+(idx===3?subType(item.o):item.c.replace(/\n/g,' '))+'</div></td>' +
      '<td style="font-size:.74rem;color:var(--muted);white-space:nowrap;">'+item.p+'</td>' +
      '<td><span class="spl '+sc(item.s)+'">'+sl(item.s)+'</span></td>' +
      '<td><button class="ai-btn" onclick="aiGen(this,\''+item.o.replace(/'/g,"\\'")+'\','+idx+')">✦ AI<span class="bf">'+FMT[idx]+'</span></button></td>' +
      '</tr>';
  });
  tb.innerHTML = html;
}

function ft(idx, status, btn) {
  btn.closest('.fbar').querySelectorAll('.fbtn').forEach(function(b){b.classList.remove('active');});
  btn.classList.add('active');
  // reset sub filter
  var subBar = document.getElementById('dp'+idx) && document.getElementById('dp'+idx).querySelector('.sub-bar');
  if (subBar) { subBar.querySelectorAll('.sbtn').forEach(function(b,i){b.classList.toggle('active',i===0);}); }
  filterRows(idx, status, 'all');
}

function subFilter(idx, sub, btn) {
  btn.closest('.sub-bar').querySelectorAll('.sbtn').forEach(function(b){b.classList.remove('active');});
  btn.classList.add('active');
  // get current status filter
  var fbar = document.getElementById('dp'+idx).querySelector('.fbar');
  var activeF = fbar ? fbar.querySelector('.fbtn.active') : null;
  var statusVal = activeF ? (activeF.classList.contains('fd')?'Finished':activeF.classList.contains('fp')?'Planned':activeF.classList.contains('fg')?'Going on':activeF.classList.contains('fn')?'__none__':'all') : 'all';
  filterRows(idx, statusVal === '__none__' ? '' : statusVal, sub);
}

function filterRows(idx, status, sub) {
  var tb = document.getElementById('tb'+idx);
  if (!tb) return;
  tb.querySelectorAll('tr').forEach(function(tr) {
    var s = tr.getAttribute('data-status') || '';
    var d = tr.getAttribute('data-sub') || '';
    var statusOk = status === 'all' || s === status;
    var subOk = !sub || sub === 'all' || d === sub;
    tr.classList.toggle('hidden', !(statusOk && subOk));
  });
}

var active = null;
function openPanel(idx) {
  document.querySelectorAll('.detail-panel').forEach(function(p){p.classList.remove('visible');});
  document.querySelectorAll('.hub-node').forEach(function(n){n.classList.remove('active');});
  document.querySelectorAll('.cat-card').forEach(function(c){c.classList.remove('active');});
  document.getElementById('placeholder').style.display = 'none';
  if (active === idx) { document.getElementById('placeholder').style.display='flex'; active=null; return; }
  document.getElementById('dp'+idx).classList.add('visible');
  document.querySelectorAll('.hub-node')[idx].classList.add('active');
  if (idx < 5) document.querySelectorAll('.cat-card')[idx] && document.querySelectorAll('.cat-card')[idx].classList.add('active');
  active = idx;
}

function aiGen(btn, name, idx) {
  var tool = AITOOL[idx] || 'AI Works';
  btn.textContent = '⏳ 생성 중...';
  btn.disabled = true;
  setTimeout(function() {
    btn.innerHTML = '✅ 완료';
    btn.style.cssText = 'background:rgba(63,185,80,.15);border-color:rgba(63,185,80,.4);color:#3fb950;';
  }, 1500);
}

function dlExcel(idx) {
  var catNames = ['기획·계획 문서','교육·운영 자료','측정·조사 도구','결과·사업 보고서','홍보·성과공유'];
  var tb = document.getElementById('tb' + idx);
  if (!tb) return;

  // Collect visible rows
  var data = [];
  data.push(['산출물명', '담당분야', '담당자', '상태']);

  tb.querySelectorAll('tr:not(.hidden)').forEach(function(tr) {
    var cells = tr.querySelectorAll('td');
    if (cells.length >= 4) {
      var name = cells[0].textContent.trim();
      var comp = cells[1].textContent.trim();
      var person = cells[2].textContent.trim();
      var status = cells[3].textContent.trim();
      data.push([name, comp, person, status]);
    }
  });

  // Create workbook
  var ws = XLSX.utils.aoa_to_sheet(data);
  ws['!cols'] = [{wch:40}, {wch:30}, {wch:12}, {wch:10}];
  var wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, '산출물');

  // Download
  var fname = catNames[idx] + '_산출물목록.xlsx';
  XLSX.writeFile(wb, fname);
}
